    },
    {
      "leaf": "Trust_In_Police",
      "score": -936,
      "confidence": 0.97,
      "reasoning": "Trust in police is at the 0.5th percentile, reinforced by past coercive-control victimization and a criminal record with pretrial supervision, creating maximum distrust."
    },
    {
      "leaf": "Anti_Corruption_Enforcement_Support",
      "score": 901,
      "confidence": 0.93,
      "reasoning": "Extremely low political trust and high populist anti-elitism, combined with a personal fraud criminal record, generate near-maximal support for rigorous anti-corruption enforcement."
    },
    {
      "leaf": "Automatic_Voter_Registration_Support",
      "score": 74,
      "confidence": 0.51,
      "reasoning": "High authoritarianism and low voting participation create mild support as a way to enforce civic duty, but low external efficacy and libertarian impulses resist government intrusion."
    },
    {
      "leaf": "Campaign_Finance_Restrictions_Support",
      "score": 756,
      "confidence": 0.83,
      "reasoning": "Populist anti-elitism, low fairness foundation, and disruptor tendencies strongly support curbing money in politics as a check on elite corruption and unfair influence."
    },
    {
      "leaf": "Electoral_Reform_Proportionality_Support",
      "score": -203,
      "confidence": 0.56,
      "reasoning": "Low openness and traditionalism make major electoral system changes unsettling, and competitive-jungle worldview views proportional representation as weakening decisive leadership."
    },
    {
      "leaf": "Judicial_Independence_Protection_Support",
      "score": -451,
      "confidence": 0.68,
      "reasoning": "Profound distrust in judiciary makes protecting its independence feel like shielding an untrusted institution from democratic accountability, despite high abstract support for rule of law."
    },
    {
      "leaf": "Trust_In_Civil_Service",
      "score": -278,
      "confidence": 0.59,
      "reasoning": "Moderate neighborhood access and some positive civic engagement experience are outweighed by very low general institutional trust and a bureaucratic skepticism born from statelessness."
    },
    {
      "leaf": "Trust_In_Electoral_Process",
      "score": -614,
      "confidence": 0.81,
      "reasoning": "Extremely low political trust and external efficacy, combined with past system contact and a competitive-jungle worldview, produce strong belief that electoral processes are rigged."
    }
  ]
}

